firmware_template.source:
#include "mqtt_tls.h"
#include <WiFiClientSecure.h>
#include <PubSubClient.h>
static WiFiClientSecure _sc;
static PubSubClient _mq(_sc);
void mqtt_tls_setup(const char*s,uint16_t p,const char*ca){_sc.setCACert(ca);_mq.setServer(s,p);Serial.printf("[mqtt_tls] %s:%d\n",s,p);}
void mqtt_tls_loop(){if(!_mq.connected())_mq.connect("parakram-tls");_mq.loop();}
bool mqtt_tls_publish(const char*t,const char*p){return _mq.publish(t,p);}
void mqtt_tls_subscribe(const char*t){_mq.subscribe(t);}
